/**
 * Runtime helper for loading committed static JSON fixtures captured during
 * the recon playbook (Step 3B — auxiliary endpoints). Use this instead of
 * re-fetching static reference data (markets, currencies, labels, etc.) on
 * every production call — these fixtures are cheap memory reads and should
 * be re-generated by re-running recon when drift is detected.
 */
import type { z } from "zod/v4";
/**
 * Loads a committed JSON fixture from the `sites/<siteId>/fixtures/<filename>`
 * directory alongside the running module and validates it with the provided Zod
 * schema. Throws on missing file or schema mismatch — both indicate the fixture
 * is stale and recon needs re-running.
 *
 * Path is resolved relative to `__dirname` so it works in both environments:
 * - Dev (`tsx src/scraper/fixtures.ts`): `__dirname` = `src/scraper/`,
 *   resolves to `src/sites/<id>/fixtures/<filename>`.
 * - Prod (`node dist/scraper/fixtures.js`): `__dirname` = `dist/scraper/`,
 *   resolves to `dist/sites/<id>/fixtures/<filename>` — which `pnpm run build`
 *   populates by copying `src/sites/` to `dist/sites/`.
 */
export declare function loadFixture<T>(siteId: string, filename: string, schema: z.ZodType<T>): T;
